def repr_frame(v) -> str:
    if isinstance(v, list):
        return "[" + ", ".join(repr_frame(x) for x in v) + "]"
    if isinstance(v, bytes):
        try:
            return v.decode("utf-8")
        except UnicodeDecodeError:
            return repr(v)
    return repr(v)


def compare(klass: str, c_reply, rust_reply) -> bool:
    if klass == "byte_exact":
        return c_reply == rust_reply
    if klass == "frame_exact":
        return _frame_eq(c_reply, rust_reply)
    if klass == "normalized":
        # TODO: load per-command normalizer from harness/oracle/normalizers/
        return c_reply == rust_reply
    if klass == "state_digest":
        # Only the final reply (DEBUG DIGEST output) matters
        return c_reply == rust_reply
    return c_reply == rust_reply


def _frame_eq(a, b) -> bool:
    if isinstance(a, list) and isinstance(b, list):
        return len(a) == len(b) and all(_frame_eq(x, y) for x, y in zip(a, b))
    return a == b


