def run_suite(c_port: int, rust_port: int | None, suite: str | None, diff_only: bool) -> int:
    cases = select_corpus(suite)
    if not cases:
        print(f"no corpus cases match suite={suite}", file=sys.stderr)
        return 2

    total = 0
    failed = 0
    for name, body in cases:
        cmds = body["commands"]
        klass = body["klass"]
        c_replies = send_commands(c_port, cmds)
        rust_replies = None
        if rust_port is not None:
            try:
                rust_replies = send_commands(rust_port, cmds)
            except Exception as e:
                print(f"{name:<22} ERROR(rust): {e}", file=sys.stderr)
                failed += 1
                total += 1
                continue
        for i, cmd in enumerate(cmds):
            total += 1
            cmd_repr = " ".join(p.decode("latin-1", errors="replace") for p in cmd)
            c_r = c_replies[i] if i < len(c_replies) else "<missing>"
            if rust_port is None:
                # No Rust server — just print the C reply for visibility
                print(f"{name:<22} [{klass}] {cmd_repr!s:<30} → C: {repr_frame(c_r)}")
                continue
            r_r = rust_replies[i] if i < len(rust_replies) else "<missing>"
            ok = compare(klass, c_r, r_r)
            if ok:
                print(f"{name:<22} [{klass}] {cmd_repr!s:<30} PASS")
            else:
                failed += 1
                print(f"{name:<22} [{klass}] {cmd_repr!s:<30} FAIL")
                print(f"  C:    {repr_frame(c_r)}")
                print(f"  Rust: {repr_frame(r_r)}")

    print()
    print(f"─── total: {total}  failed: {failed} ───")
    if rust_port is None:
        print("(Rust server unavailable — observed C behavior only.)")
        return 0  # not an error; expected during pre-Phase-2 scaffolding
    if diff_only:
        return 3 if failed else 0
    return 1 if failed else 0


def main() -> int:
    ap = argparse.ArgumentParser()
    ap.add_argument("--suite", default=None,
                    help="Run only this suite (e.g. smoke, protocol, strings). Default: all.")
    ap.add_argument("--c-port", type=int, default=None,
                    help="Use already-running C server on this port (else spawn).")
    ap.add_argument("--rust-port", type=int, default=None,
                    help="Use already-running Rust server on this port (else spawn if binary exists).")
    ap.add_argument("--diff-only", action="store_true",
                    help="Print diffs without failing (returns 3 on diff, 0 on match).")
    ap.add_argument("--check-infrastructure", action="store_true",
                    help="Just verify the C server starts and accepts commands; don't run corpus.")
    args = ap.parse_args()

    if not VALKEY_BIN.exists() and args.c_port is None:
        print(f"ERROR: Valkey binary not built at {VALKEY_BIN}", file=sys.stderr)
        print("       Run: ./harness/bootstrap-upstream.sh", file=sys.stderr)
        print("       Then: cd reference/valkey && make -j4 BUILD_TLS=no DISABLE_WERRORS=yes", file=sys.stderr)
        return 2

    rust_available = args.rust_port is not None or RUST_BIN.exists()

    # Spawn or use existing
    if args.c_port is not None:
        c_port = args.c_port
        c_cm = contextlib.nullcontext(c_port)
    else:
        c_port = pick_free_port()
        c_cm = spawn_server(VALKEY_BIN, c_port, "valkey")

    if args.rust_port is not None:
        rust_port = args.rust_port
        rust_cm = contextlib.nullcontext(rust_port)
    elif RUST_BIN.exists():
        rust_port = pick_free_port()
        rust_cm = spawn_server(RUST_BIN, rust_port, "rust")
    else:
        rust_port = None
        rust_cm = contextlib.nullcontext(None)

    with c_cm as c_p, rust_cm as r_p:
        if args.check_infrastructure:
            # Just verify C reachable
            replies = send_commands(c_p, [[b"PING"]])
            ok = replies and replies[0] == b"+PONG"
            print(f"infrastructure: c={ok}  rust={'yes' if r_p is not None else 'no-binary'}")
            return 0 if ok else 2
        return run_suite(c_p, r_p, args.suite, args.diff_only)


